  `user_id` bigint NOT NULL COMMENT '用户ID',
  `device_id` bigint NOT NULL COMMENT '设备ID',
  `station_id` bigint NOT NULL COMMENT '场站ID',
  `order_type` tinyint DEFAULT '1' COMMENT '订单类型: 1-普通充电 2-预约充电 3-V2G放电',
  `start_time` datetime NOT NULL COMMENT '充电开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '充电结束时间',
  `total_energy` decimal(10,2) DEFAULT '0.00' COMMENT '总充电量(kWh)',
  `total_duration` int DEFAULT '0' COMMENT '总时长(分钟)',
  `electricity_fee` decimal(10,2) DEFAULT '0.00' COMMENT '电费',
  `service_fee` decimal(10,2) DEFAULT '0.00' COMMENT '服务费',
  `parking_fee` decimal(10,2) DEFAULT '0.00' COMMENT '占位费',
  `total_fee` decimal(10,2) DEFAULT '0.00' COMMENT '总费用',
  `discount_fee` decimal(10,2) DEFAULT '0.00' COMMENT '优惠金额',
  `actual_fee` decimal(10,2) DEFAULT '0.00' COMMENT '实付金额',
  `payment_status` tinyint DEFAULT '0' COMMENT '支付状态: 0-未支付 1-已支付 2-退款中 3-已退款',
  `payment_method` tinyint DEFAULT NULL COMMENT '支付方式: 1-微信 2-支付宝 3-余额 4-刷卡',
  `payment_time` datetime DEFAULT NULL COMMENT '支付时间',
  `invoice_status` tinyint DEFAULT '0' COMMENT '发票状态: 0-未申请 1-已申请 2-已开具',
  `status` tinyint DEFAULT '0' COMMENT '状态: 0-充电中 1-已完成 2-异常终止 3-已取消',
  `operator_id` bigint DEFAULT NULL COMMENT '操作员ID',
  `refund_amount` decimal(10,2) DEFAULT NULL COMMENT '退款金额',
  `refund_reason` varchar(500) DEFAULT NULL COMMENT '退款原因',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `idx_order_no` (`order_no`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_station_id` (`station_id`),
  KEY `idx_start_time` (`start_time`),
  KEY `idx_status` (`status`),
  KEY `idx_payment_status` (`payment_status`)
) ENGINE=InnoDB AUTO_INCREMENT=220 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='充电订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

