--
-- Table structure for table `charging_session`
--

DROP TABLE IF EXISTS `charging_session`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `charging_session` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '会话ID',
  `order_id` bigint NOT NULL COMMENT '订单ID',
  `device_id` bigint NOT NULL COMMENT '设备ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `current_power` decimal(10,2) DEFAULT NULL COMMENT '当前功率(kW)',
  `current_voltage` decimal(10,2) DEFAULT NULL COMMENT '当前电压(V)',
  `current_current` decimal(10,2) DEFAULT NULL COMMENT '当前电流(A)',
  `current_soc` decimal(5,2) DEFAULT NULL COMMENT '当前电池SOC(%)',
  `target_soc` decimal(5,2) DEFAULT NULL COMMENT '目标SOC(%)',
  `charged_energy` decimal(10,2) DEFAULT NULL COMMENT '已充电量(kWh)',
  `charged_duration` int DEFAULT NULL COMMENT '已充时长(分钟)',
  `current_cost` decimal(10,2) DEFAULT NULL COMMENT '当前费用',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1-充电中 2-即将结束 3-已结束',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
